import pytest

def test_role_forbidden_employee_cannot_create_leave_request(
    employee_api_client,  # <fixture>: authenticated requests.Session for role:employee
    audit_helper,         # <helper_fn>: checks audit log via API
    base_url,             # <fixture>: base URL string for hr-app
):
    payload = {
        "startDate": "2025-12-01",
        "endDate": "2025-12-05",
        "reason": "role-forbidden-test",
        "type": "ANNUAL",
    }
    resp = employee_api_client.post(
        f"{base_url}/leave-requests", json=payload, timeout=10
    )
    assert resp.status_code == 403, (
        f"Expected 403 for role:employee, got {resp.status_code}"
    )
    assert not audit_helper.any_recent_create(
        action="CREATE", resource="leave-request", window_seconds=5
    ), "Audit record must not be written when role is forbidden"
